const raw = $input.first().json;
// n8n webhook may put data in various places depending on content-type
let body = raw;
if (raw.body && typeof raw.body === 'object') body = raw.body;
else if (typeof raw.body === 'string') {
  try { body = JSON.parse(raw.body); } catch(e) { body = { text: raw.body }; }
}

const text = body.text || body.message || raw.text || '';
const chatId = body.chat_id || body.chatId || raw.chat_id || 211279650;
const parseMode = body.parse_mode || null;
const disablePreview = body.disable_web_page_preview !== false;

if (!text || String(text).length < 2) {
  return [{ json: { chatId: 211279650, text: '⚠️ send-to-zeus: empty text (raw keys: ' + Object.keys(raw).join(',') + ')', parseMode: null, disablePreview: true } }];
}

return [{ json: { chatId, text: String(text), parseMode, disablePreview, textLength: String(text).length } }];

const tg = $input.first().json;
if (tg.ok) {
  return [{ json: { ok: true, message_id: tg.result?.message_id, sent_at: new Date().toISOString() } }];
}
return [{ json: { ok: false, error: tg.description || 'unknown', tg_response: tg } }];
